<script>
  document.addEventListener("DOMContentLoaded", function () {
    // Handle View button
    document.querySelectorAll(".viewBtn").forEach(btn => {
      btn.addEventListener("click", function () {
        let row = this.closest("tr");
        document.getElementById("viewPermit").innerText = row.querySelector(".permit").innerText;
        document.getElementById("viewDatetime").innerText = row.querySelector(".datetime").innerText;
        document.getElementById("viewDescription").innerText = row.querySelector(".description").innerText;
        document.getElementById("viewStatus").innerText = row.querySelector(".status").innerText;
      });
    });
  });
</script>
  
